form:Form.form:Scripts:
		function LoadForm()
{	
	if(Ctrl('estado_sancion').GetXValue() != "A")
			CtrlEnabled('INTERRUMPIR', false);
	if(Ctrl('LIST'))
		ChangeSelect();
	else
	{
		if(Ctrl('f_fechahora_int').GetXValue() != "")
			CtrlEnabled('INTERRUMPIR', false);				
	}
}

function ChangeSelect()
{
	if(Ctrl("LIST").GetSelectAttrValue("f_fechahora_int")!="")
		CtrlEnabled('INTERRUMPIR', false);
	else if(Ctrl('estado_sancion').GetXValue() == "A")
		CtrlEnabled('INTERRUMPIR', true);
}
